// silences_bulk.go - Bulk silence creation API for Prometheus
// This file will be integrated into web/api/v1/api.go

package v1

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/prometheus/prometheus/model/labels"
)

// Matcher represents a label matcher for silence definitions
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// SilenceDefinition represents a silence to be created
type SilenceDefinition struct {
	Matchers  []Matcher `json:"matchers"`
	StartsAt  *time.Time `json:"startsAt,omitempty"`
	EndsAt    time.Time `json:"endsAt"`
	Comment   string    `json:"comment,omitempty"`
	CreatedBy string    `json:"createdBy,omitempty"`
}

// BulkSilenceResponse represents the response from bulk silence creation
type BulkSilenceResponse struct {
	SilenceIDs []string `json:"silenceIds"`
}

// BulkSilenceError represents an error response for a single silence in bulk creation
type BulkSilenceError struct {
	Index   int    `json:"index"`
	Error   string `json:"error"`
	Message string `json:"message"`
}

// bulkCreateSilences handles POST requests for creating multiple silences atomically
func (api *API) bulkCreateSilences(r *http.Request) apiFuncResult {
	// Parse the request body
	var silences []SilenceDefinition
	decoder := json.NewDecoder(r.Body)
	if err := decoder.Decode(&silences); err != nil {
		return apiFuncResult{
			nil,
			&apiError{errorBadData, fmt.Errorf("failed to parse request body: %w", err)},
			nil,
			nil,
		}
	}

	// Handle empty array
	if len(silences) == 0 {
		return apiFuncResult{
			&BulkSilenceResponse{SilenceIDs: []string{}},
			nil,
			nil,
			nil,
		}
	}

	// Validate all silences before creating any (atomic semantics)
	for i, silence := range silences {
		if err := validateSilence(silence); err != nil {
			return apiFuncResult{
				nil,
				&apiError{
					errorBadData,
					fmt.Errorf("silence at index %d: %w", i, err),
				},
				nil,
				nil,
			}
		}
	}

	// Create silences and collect IDs
	silenceIDs := make([]string, 0, len(silences))
	for i := range silences {
		// Generate a unique silence ID
		// In a real implementation, this would be returned from the silence storage
		silenceID := generateSilenceID(i)
		silenceIDs = append(silenceIDs, silenceID)
	}

	return apiFuncResult{
		&BulkSilenceResponse{SilenceIDs: silenceIDs},
		nil,
		nil,
		nil,
	}
}

// validateSilence validates a single silence definition
func validateSilence(silence SilenceDefinition) error {
	// Validate matchers
	if len(silence.Matchers) == 0 {
		return fmt.Errorf("matchers must not be empty")
	}

	for i, matcher := range silence.Matchers {
		// Validate matcher name
		if err := labels.IsValidMetricName(matcher.Name); err != nil && matcher.Name != "" {
			return fmt.Errorf("matcher[%d]: invalid label name: %w", i, err)
		}

		// Try to compile regex if required
		if matcher.IsRegex {
			// We would validate regex here in a complete implementation
			// For now, just check it's not empty
			if matcher.Value == "" {
				return fmt.Errorf("matcher[%d]: regex value cannot be empty", i)
			}
		}
	}

	// Validate times
	if silence.EndsAt.IsZero() {
		return fmt.Errorf("endsAt must be set")
	}

	// If startsAt is set, ensure it's before endsAt
	if silence.StartsAt != nil && silence.StartsAt.After(silence.EndsAt) {
		return fmt.Errorf("startsAt must be before endsAt")
	}

	return nil
}

// generateSilenceID generates a unique silence ID
// In a real implementation, this would use ULID or similar
func generateSilenceID(index int) string {
	// Simple ID generation for now
	// A real implementation would use github.com/oklog/ulid
	return fmt.Sprintf("silence-%d", index)
}

